var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"이런 걸 인간들은 반항기라고 부르더라. 시간이 많이 흐르긴 했나 봐.","JPN":"人間って、こういうのを反抗期って呼ぶらしいよ。いつの間にかだいぶ時間が経ってたんだね。","ENG":"So this is what humans call \\"the rebellious phase\\"... It appears that a long time has passed.","TWN":"這就是人類所謂的叛逆期，都已經過這麼久啦？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"참 희한해. 말이 통하는 나는 미움 받고, 말이 안 통하던 너는 받아 주고.","JPN":"おかしいよね。言葉が通じる私は嫌われたのに、言葉が通じなかったあなたは受け入れられてさ。","ENG":"Isn't it strange? How come they despise me when I can get along with them, but accept you when you can't even understand them?","TWN":"真稀奇，能溝通的我被討厭，卻接受無法溝通的你。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"내 위장용 코디가 그렇게 티나나 하면 그것도 아닌데~","JPN":"変装した時のコーディネートが下手ってわけでもないと思うのに～","ENG":"It's not like my disguise was that obvious, is it?","TWN":"而且我的造型偽裝得那麼好～"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"네 그런 점이 거리를 두게 만드는 원인이라고 생각한 적은 없나?","JPN":"お前のそういうところが遠ざけられる原因だと思ったことはないのか？","ENG":"Haven't you ever thought that's what keeps you at their arm's length?","TWN":"你有沒有想過，這就是讓我和你產生距離的原因？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에이. 인간들은 원래 날것 그대로를 싫어하는걸.","JPN":"ええ～人間って元々ありのままが嫌いなんだもん。","ENG":"Oh, please. You know how humans hate seeing things for what they are.","TWN":"哎呀，人類本來就討厭原本的樣子。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"처음부터 종 자체가 달라서 문제야. 난 그냥 그렇다고 믿을래.","JPN":"最初から種が違うのが問題なんだよ。そうだって信じることにする。","ENG":"It's because we're of different races to begin with. Or at least, that's what I'd like to believe.","TWN":"打從一開始，問題就出在種類不同。我寧願相信是那樣。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"……먼저 가서 기다리고 있어라.","JPN":"……先に行って待ってろ。","ENG":"…You go first and wait for me there.","TWN":"……你先去等我。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"내가 너를 물어뜯을 수 있게 되었을 때, 다시 찾아가겠다.","JPN":"私がお前を噛みちぎれるようになった時、また訪ねよう。","ENG":"I'll come back to you when I'm able to bite you off.","TWN":"等到我能咬住你的時候，會再去找你。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"흐흥. 그냥 여기서 평생 인간들이랑 지내셔.","JPN":"ふふん。ここで人間たちと一生暮らしなさいよ。","ENG":"Hehe. No, you should just stay here with the humans for the rest of your life.","TWN":"哼哼，你就一輩子和人類在這裡生活吧。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>내</color>가 되어 봤자 두려움만 살 뿐이라는 건, 너도 이제 알 거 아냐.","JPN":"<color=#ffd34c>私</color>になっても怖がられるだけだってこと、あなたももう知ってるでしょ？","ENG":"I know that you must have realized by now that becoming <color=#ffd34c>me</color> will only invoke fear in them.","TWN":"你現在不是也知道，就算成為<color=#ffd34c>我</color>，也只能活在恐懼裡。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"참 딱하기도 하지. 겨우 스쳐 지나가는 인간들의 원망을 꾸역꾸역 삼키고 있었으니.","JPN":"可哀想よね。すれ違っただけの人間の恨みを無理やり飲み込んでいたなんて。","ENG":"You were swallowing your resentment for them all this time. What a pity.","TWN":"真慘，好不容易才吞掉人類的怨恨。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"기억해? 예전의 레비아탄은 무적이었던 거 있지?","JPN":"覚えてる？　昔のレヴィアタンは無敵だったってこと。","ENG":"Do you still remember? When Leviathan was invincible?","TWN":"你還記得嗎？以前的利維坦是無敵的。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"둘이서 하나라 외롭지 않아. 아무 생각 없이 사냥만 즐기면 그만이었던 거야.","JPN":"二人で一人だから寂しくなかった。ただ何も考えずに楽しく狩るだけでよかったもん。","ENG":"We were one and never lonely. All we did was enjoy the thrill of the hunt.","TWN":"因為二個就是一體，所以一點都不孤單。什麼都不用想，只要盡情享受狩獵就好。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"인간들에게 의존해야 하는 삶 따위는, 레비아탄에게 언빌리버블한 일이라구.","JPN":"人間に頼らなければいけない人生なんて、レヴィアタンにはアンビリバボーなことだよ。","ENG":"But having to rely on humans... That's something unthinkable for Leviathan.","TWN":"必須依賴人類的生活，對利維坦而言簡直不可思議。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"그래도 나는 지금이 더 낫다.","JPN":"それでも私は今の方がいい。","ENG":"Still, I like this better.","TWN":"但我更喜歡現在。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어째서?","JPN":"なんで？","ENG":"But why?","TWN":"為什麼？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"이 아이가 나와 마시멜로를 나눠 먹었으니까.","JPN":"この子と一緒にマシュマロを食べたから。","ENG":"Because this child shares her marshmallows with me.","TWN":"因為她會跟我分享棉花糖。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};